import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { LineChart } from '@mui/x-charts';
import response from './response.json';

interface GoldenHour {
  morning: string;
  evening: string;
}

interface DayLightTrend {
  date: string;
  dayLength: string;
}

interface WidgetData {
  location: string;
  current: {
    sunrise: string;
    sunset: string;
    dayLength: string;
    goldenHour: GoldenHour;
  };
  dayLightTrend: DayLightTrend[];
}

export default function Widget() {
  const widgetData = response.data as WidgetData;

  const dayLengths = widgetData.dayLightTrend.map((trend) => {
    const [hours, minutes] = trend.dayLength.split('h ').map((val) => parseInt(val));
    return hours * 60 + minutes;
  });

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 450, bgcolor: '#FFEB3B' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" color="text.primary">
              Sunrise & Sunset
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {widgetData.location}
            </Typography>
            <Typography variant="body2" sx={{ mt: 1 }}>
              Sunrise: {widgetData.current.sunrise}
            </Typography>
            <Typography variant="body2">
              Sunset: {widgetData.current.sunset}
            </Typography>
            <Typography variant="body2" sx={{ mt: 1 }}>
              Day Length: {widgetData.current.dayLength}
            </Typography>
            <Typography variant="body2">
              Golden Hour: {widgetData.current.goldenHour.morning} / {widgetData.current.goldenHour.evening}
            </Typography>
          </Box>

          <Box>
            <LineChart
              height={100}
              series={[
                {
                  data: dayLengths,
                  color: '#FFA726',
                  curve: 'natural',
                  showMark: false,
                },
              ]}
              xAxis={[{ data: widgetData.dayLightTrend.map((trend) => trend.date), hide: true }]}
              margin={{ top: 10, bottom: 10, left: 10, right: 10 }}
              sx={{
                '& .MuiLineElement-root': {
                  strokeWidth: 2,
                },
              }}
            />
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
